/**
 * @summary Get live trend status and top movers
 */
export const getGetLiveTrendsUrl = () => {
  return `/api/trends/live`;
};

export const getLiveTrends = async (
  options?: RequestInit,
): Promise<LiveTrends> => {
  return customFetch<LiveTrends>(getGetLiveTrendsUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetLiveTrendsQueryKey = () => {
  return [`/api/trends/live`] as const;
};

export const getGetLiveTrendsQueryOptions = <
  TData = Awaited<ReturnType<typeof getLiveTrends>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getLiveTrends>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetLiveTrendsQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getLiveTrends>>> = ({
    signal,
  }) => getLiveTrends({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getLiveTrends>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetLiveTrendsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getLiveTrends>>
>;
export type GetLiveTrendsQueryError = ErrorType<unknown>;

/**
 * @summary Get live trend status and top movers
 */

export function useGetLiveTrends<
  TData = Awaited<ReturnType<typeof getLiveTrends>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getLiveTrends>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetLiveTrendsQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Delete an alert
 */
export const getDeleteAlertUrl = (id: number) => {
  return `/api/alerts/${id}`;
};

export const deleteAlert = async (
  id: number,
  options?: RequestInit,
): Promise<void> => {
  return customFetch<void>(getDeleteAlertUrl(id), {
    ...options,
    method: "DELETE",
  });
};

export const getDeleteAlertMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof deleteAlert>>,
    TError,
    { id: number },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof deleteAlert>>,
  TError,
  { id: number },
  TContext
> => {
  const mutationKey = ["deleteAlert"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof deleteAlert>>,
    { id: number }
  > = (props) => {
    const { id } = props ?? {};

    return deleteAlert(id, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type DeleteAlertMutationResult = NonNullable<
  Awaited<ReturnType<typeof deleteAlert>>
>;

export type DeleteAlertMutationError = ErrorType<unknown>;

/**
 * @summary Delete an alert
 */
export const useDeleteAlert = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof deleteAlert>>,
    TError,
    { id: number },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof deleteAlert>>,
  TError,
  { id: number },
  TContext
> => {
  return useMutation(getDeleteAlertMutationOptions(options));
};
